function trackBlogEngagement(){let n=0;window.addEventListener("scroll",function(){const t=Math.round(window.scrollY/(document.body.scrollHeight-window.innerHeight)*100);n<t&&(n=t,n%25===0&&typeof gtag<"u"&&gtag("event","scroll_depth",{event_category:"Blog Engagement",event_label:n+"%",value:n}))});const e=Date.now();window.addEventListener("pagehide",function(){const t=Math.round((Date.now()-e)/1e3);t>10&&typeof gtag<"u"&&gtag("event","reading_time",{event_category:"Blog Engagement",event_label:"Time on Page",value:t})}),document.addEventListener("click",function(t){if(t.target.matches(".experimental-share-btn, .share-btn")&&typeof gtag<"u"){const a=t.target.classList.contains("facebook")?"Facebook":t.target.classList.contains("twitter")?"Twitter":t.target.classList.contains("linkedin")?"LinkedIn":"Unknown";gtag("event","social_share",{event_category:"Social Media",event_label:a,value:1})}}),document.addEventListener("click",function(t){t.target.matches('a[href*="bansallawyers.com.au"]')&&typeof gtag<"u"&&gtag("event","internal_link_click",{event_category:"Navigation",event_label:t.target.href,value:1})}),document.addEventListener("submit",function(t){t.target.matches('form[action*="contact"], form[id*="contact"], form[class*="contact"]')&&typeof gtag<"u"&&gtag("event","contact_form_submit",{event_category:"Lead Generation",event_label:"Contact Form",value:1})}),document.addEventListener("DOMContentLoaded",function(){document.querySelectorAll('form[action*="contact"], form[id*="contact"], form[class*="contact"]').length>0&&typeof gtag<"u"&&gtag("event","contact_form_view",{event_category:"Lead Generation",event_label:"Form Displayed"})})}document.addEventListener("DOMContentLoaded",trackBlogEngagement);function toggleFAQ(n){const e=document.getElementById("faq-answer-"+n),t=document.getElementById("faq-icon-"+n);!e||!t||(e.style.maxHeight==="0px"||e.style.maxHeight===""?(e.style.maxHeight=e.scrollHeight+"px",e.style.padding="0 20px",t.textContent="\u2212",t.style.transform="rotate(180deg)"):(e.style.maxHeight="0px",e.style.padding="0 20px",t.textContent="+",t.style.transform="rotate(0deg)"))}
